exploreUrl:
@js:
sort = [];
push = (title, url, type) => sort.push({
  title: title,
  url: url,
  style: {
    layout_flexGrow: 1,
    layout_flexBasisPercent: type
  }
});
$ = (x) => `search?${x}&orderType=1&page={{page}}&searchType=1&size=42`;
u = source.key;
push("・排行榜・", null, 1);
["周榜", "月榜", "年榜", "总榜"].map((p, q) => {
  push(p, `rank?type=${q + 1}`, null);
});
[["题材", "category"],
["CV", "author"]].map([a, b] => {
  push(`・${a}・`, $(""), 1);
  d = /y/.test(b) ? "categories": "authors";
  c = JSON.parse(java.ajax(u + d)).model;
  for (i = 0; i < c.length; ++i) {
    push(
      c[i].name,
      $(b + "=" + encodeURIComponent(c[i].name)),
      null
    );
  };
});
JSON.stringify(sort);

@js:
u = source.key;
sort = [];
push = (title, url, type) => sort.push({
  title: title,
  url: url,
  style: {
    layout_flexGrow: 1,
    layout_flexBasisPercent: type
  }
});
J = org.jsoup.Jsoup.parse(java.ajax(u));
push("・分类・", null, 1);
X = J.select('.menu a');
for (i = 0; i < X.length; ++i) {
  push(
    X[i].text(),
    X[i].attr('href') + "<,index_{{page}}.html>",
    null
  );
};
push("・标签・", null, 1);
Y = J.select('.panel-default a');
for (i = 0; i < Y.length; ++i) {
  push(
    Y[i].text(),
    String(Y[i].attr('href')).replace(/\d+\.html$/,'{{page-1}}.html'),
    null
  );
};
push("・书单・", null, 1);
K = org.jsoup.Jsoup.parse(java.ajax(u + "/shudan"));
Z = K.select('.panel-warning .list-group-item a');
for (i = 0; i < Z.length; ++i) {
  push(
    Z[i].text(),
    Z[i].attr('href'),
    null
  );
};
p = K.select('.m-page .disabled').text().match(/\/(\d+)/)[1];
for (i = 2; i <= p; ++i) {
  M = org.jsoup.Jsoup.parse(java.ajax(u + `/shudan/index_${i}.html`));
  N = M.select('.panel-warning .list-group-item a');
  for (o = 0; o < N.length; ++o) {
    push(
    N[o].text(),
    N[o].attr('href'),
    null
    );
  };
};
JSON.stringify(sort);

